import React from 'react';
import { motion } from 'framer-motion';

const MiraOrb = ({ onClick, className = '' }) => {
  return (
    <motion.div
      className={`relative cursor-pointer group ${className}`}
      onClick={onClick}
      whileHover={{ scale: 1.05 }}
      whileTap={{ scale: 0.95 }}
      data-testid="mira-orb"
    >
      {/* Outer Ambient Glow - The 'Aura' */}
      <motion.div
        className="absolute inset-0 rounded-full blur-3xl opacity-40 group-hover:opacity-60 transition-opacity duration-700"
        style={{
          background: 'radial-gradient(circle, rgba(124,58,237,0.6) 0%, rgba(76,29,149,0.3) 50%, transparent 70%)',
          transform: 'scale(1.5)',
        }}
        animate={{
          scale: [1.4, 1.6, 1.4],
          opacity: [0.3, 0.5, 0.3],
        }}
        transition={{
          duration: 6,
          repeat: Infinity,
          ease: "easeInOut",
        }}
      />

      {/* The Core Entity */}
      <div className="relative w-20 h-20 rounded-full overflow-hidden shadow-2xl ring-1 ring-white/10 backdrop-blur-sm">
        {/* Deep Space Background */}
        <div className="absolute inset-0 bg-[#0a0a12]" />

        {/* Moving Internal Light - The 'Intelligence' */}
        <motion.div
          className="absolute inset-[-50%] opacity-70"
          style={{
            background: 'conic-gradient(from 0deg, transparent 0%, rgba(139, 92, 246, 0.5) 20%, transparent 40%, rgba(56, 189, 248, 0.3) 60%, transparent 100%)',
            filter: 'blur(12px)',
          }}
          animate={{
            rotate: 360,
          }}
          transition={{
            duration: 10,
            repeat: Infinity,
            ease: "linear",
          }}
        />

        {/* Inner Core Highlight */}
        <motion.div
          className="absolute inset-0 rounded-full"
          style={{
            background: 'radial-gradient(circle at 30% 30%, rgba(255,255,255,0.15) 0%, transparent 60%)',
          }}
        />

        {/* Subtle Pulse Overlay */}
        <motion.div
            className="absolute inset-0 bg-violet-500/10 rounded-full"
            animate={{ opacity: [0, 0.2, 0] }}
            transition={{ duration: 4, repeat: Infinity, ease: "easeInOut" }}
        />
      </div>
    </motion.div>
  );
};

export default MiraOrb;
